import{_ as e,o as a,c as o,a2 as d}from"./chunks/framework.kxxRO88J.js";const p=JSON.parse('{"title":"2장. 환경 설정","description":"","frontmatter":{"sidebar_position":1},"headers":[],"relativePath":"02-setup/index.md","filePath":"02-setup/index.md"}'),r={name:"02-setup/index.md"};function i(l,t,n,h,s,m){return a(),o("div",null,[...t[0]||(t[0]=[d('<h1 id="_2장-환경-설정" tabindex="-1">2장. 환경 설정 <a class="header-anchor" href="#_2장-환경-설정" aria-label="Permalink to &quot;2장. 환경 설정&quot;">​</a></h1><h2 id="총-소요-시간-약-30분" tabindex="-1">총 소요 시간: 약 30분 <a class="header-anchor" href="#총-소요-시간-약-30분" aria-label="Permalink to &quot;총 소요 시간: 약 30분&quot;">​</a></h2><p>이 챕터에서는 Remotion과 Codex를 실제로 사용하기 위한 모든 도구를 설치합니다. 각 단계를 순서대로 따라하면 챕터 끝에서 첫 번째 Remotion 영상을 렌더링할 수 있습니다.</p><p>이미 Node.js와 Codex CLI가 설치된 환경이라면 <a href="./install-remotion.html">3단계: Remotion 프로젝트 생성</a>부터 시작하셔도 됩니다.</p><hr><h2 id="이-챕터의-구성" tabindex="-1">이 챕터의 구성 <a class="header-anchor" href="#이-챕터의-구성" aria-label="Permalink to &quot;이 챕터의 구성&quot;">​</a></h2><table tabindex="0"><thead><tr><th>단계</th><th>내용</th><th>소요 시간</th></tr></thead><tbody><tr><td><a href="./prerequisites.html">1. 사전 준비 사항</a></td><td>Node.js, Bun, FFmpeg, API 키</td><td>10분</td></tr><tr><td><a href="./install-remotion.html">2. Remotion 프로젝트 생성</a></td><td><code>bun create video</code>로 프로젝트 시작</td><td>5분</td></tr><tr><td><a href="./install-codex.html">3. Codex 설치 및 연동</a></td><td>Codex CLI + Remotion 스킬 28개</td><td>10분</td></tr><tr><td><a href="./hello-remotion.html">4. 첫 번째 영상 렌더링</a></td><td>Codex로 코드 수정 → MP4 출력</td><td>5분</td></tr></tbody></table><hr><h2 id="이-챕터를-마치면" tabindex="-1">이 챕터를 마치면 <a class="header-anchor" href="#이-챕터를-마치면" aria-label="Permalink to &quot;이 챕터를 마치면&quot;">​</a></h2><ul><li>Node.js 24+, Bun, FFmpeg가 정상 동작하는 환경</li><li>OpenAI API 키가 Codex CLI에 연결된 상태</li><li>Remotion 프로젝트가 생성되고 Studio가 브라우저에서 열리는 상태</li><li>Codex에 Remotion 문서 MCP와 28개 스킬이 설치된 상태</li><li>첫 번째 MP4 파일이 로컬에 렌더링된 상태</li></ul><p>모든 준비가 완료되면 3장에서 본격적으로 Codex 프롬프트로 모션 그래픽을 만들기 시작합니다.</p>',11)])])}const _=e(r,[["render",i]]);export{p as __pageData,_ as default};
